from abc import ABC, abstractmethod

class A(ABC):
    @classmethod
    @property
    @abstractmethod
    def f(cls):
        '''Some abstract class property.'''
        return 'property'

# Test the import_object logic
import inspect

def import_object(modname, objpath):
    import importlib
    module = importlib.import_module(modname)
    obj = module
    parent = None
    for attrname in objpath:
        parent = obj
        obj = getattr(obj, attrname)

        # Our fix
        if isinstance(parent, type):
            for cls in inspect.getmro(parent):
                if attrname in cls.__dict__:
                    dict_entry = cls.__dict__[attrname]
                    if isinstance(dict_entry, classmethod) and isinstance(dict_entry.__func__, property):
                        obj = dict_entry.__func__
                    break

    return obj

obj = import_object('__main__', ['A', 'f'])
print(f'obj: {obj}')
print(f'isinstance property: {isinstance(obj, property)}')
print(f'doc: {obj.__doc__}')
print(f'isabstractmethod: {getattr(obj, \"__isabstractmethod__\", False)}')
print(f'fget: {obj.fget}')

assert isinstance(obj, property)
assert obj.__doc__ == 'Some abstract class property.'
assert getattr(obj, '__isabstractmethod__', False) == True
print('All tests passed!')
"
