# In Python 3.9+, you can do:
class A:
    _value = 'hello'

    @classmethod
    @property
    def f(cls):
        '''Some class property.'''
        return cls._value

    @classmethod
    @f.setter
    def f(cls, value):
        cls._value = value

# But this doesn't work because f is a classmethod object, not a property object
# The correct way is:
p = property(lambda cls: cls._value)
p = p.setter(lambda cls, value: setattr(cls, '_value', value))
A.f = classmethod(p)

print('A.__dict__[\"f\"]:', A.__dict__['f'])
print('type:', type(A.__dict__['f']))
print('__func__:', A.__dict__['f'].__func__)
print('type of __func__:', type(A.__dict__['f'].__func__))
print('fget:', A.__dict__['f'].__func__.fget)
print('fset:', A.__dict__['f'].__func__.fset)
"
"}

